/**
 * Notification log model — tracks sent notification history.
 *
 * Each log entry captures the full context of a notification delivery attempt:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  status: DeliveryStatus;
  error?: string;
  createdAt: Date;
}

export interface NotificationLogQuery {
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      createdAt: new Date(record['createdAt'] as string),
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      status: entity.status,
      error: entity.error,
      createdAt: entity.createdAt.toISOString(),
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.createdAt >= startDate && log.createdAt <= endDate,
    );
  }
}

/**
 * Notification history service — logs and queries notification delivery history.
 *
 * Integrates with the notification system via EventBus, listening for
 * notification:sent and notification:failed events to automatically log
 * all delivery attempts.
 *
 * Provides query methods for retrieving notification history by recipient,
 * type, channel, status, and date range.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
import type { NotificationLog, NotificationLogQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private repository: NotificationLogRepository,
    private eventBus: EventBus,
  ) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.logNotification(event.notification, 'sent');
    });

    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.logNotification(event.notification, 'failed', event.error);
    });
  }

  private logNotification(
    notification: { id: string; recipient: string; channel: string; type: string; subject: string },
    status: 'sent' | 'failed',
    error?: string,
  ): void {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel as NotificationLog['channel'],
      type: notification.type as NotificationLog['type'],
      subject: notification.subject,
      status,
      error,
      createdAt: new Date(),
    };

    this.repository.save(log);
    this.logger.info(
      `Logged ${status} notification ${notification.id} to ${notification.recipient} [${notification.channel}]`,
    );
  }

  query(filters: NotificationLogQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.type && log.type !== filters.type) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.startDate && log.createdAt < filters.startDate) return false;
      if (filters.endDate && log.createdAt > filters.endDate) return false;
      return true;
    });
  }

  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  getByChannel(channel: NotificationLog['channel']): NotificationLog[] {
    return this.repository.findByChannel(channel);
  }

  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  getAll(): NotificationLog[] {
    return this.repository.findAll();
  }

  getCount(): number {
    return this.repository.count();
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import type { Notification } from '../../src/models/notification.js';

function makeNotification(overrides?: Partial<Notification>): Notification {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: ord-001',
    body: 'Your order has been placed.',
    status: 'sent',
    sentAt: new Date(),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repo: NotificationLogRepository;
  let eventBus: EventBus;
  let service: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repo = new NotificationLogRepository(db);
    eventBus = new EventBus();
    service = new NotificationHistoryService(repo, eventBus);
    resetNotificationLogIdCounter();
  });

  describe('automatic logging via events', () => {
    it('should log a sent notification when notification:sent event is emitted', async () => {
      const notification = makeNotification();

      await eventBus.emit({
        type: 'notification:sent',
        notification,
        timestamp: new Date(),
      });

      const logs = service.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.notificationId).toBe('notif-0001');
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.type).toBe('order_confirmation');
      expect(logs[0]!.subject).toBe('Order Confirmation: ord-001');
      expect(logs[0]!.status).toBe('sent');
      expect(logs[0]!.error).toBeUndefined();
    });

    it('should log a failed notification when notification:failed event is emitted', async () => {
      const notification = makeNotification({ status: 'failed' });

      await eventBus.emit({
        type: 'notification:failed',
        notification,
        error: 'Connection timeout',
        timestamp: new Date(),
      });

      const logs = service.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('failed');
      expect(logs[0]!.error).toBe('Connection timeout');
    });

    it('should generate sequential IDs for log entries', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002' }),
        timestamp: new Date(),
      });

      const logs = service.getAll();
      expect(logs[0]!.id).toBe('nlog-0001');
      expect(logs[1]!.id).toBe('nlog-0002');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:failed',
        notification: makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }),
        error: 'Invalid email',
        timestamp: new Date(),
      });

      expect(service.getCount()).toBe(2);
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ recipient: 'alice@example.com' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }),
        timestamp: new Date(),
      });

      const aliceLogs = service.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]!.recipient).toBe('alice@example.com');
    });

    it('should return empty array for unknown recipient', () => {
      expect(service.getByRecipient('unknown@example.com')).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ type: 'order_confirmation' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', type: 'welcome' }),
        timestamp: new Date(),
      });

      const orderLogs = service.getByType('order_confirmation');
      expect(orderLogs).toHaveLength(1);
      expect(orderLogs[0]!.type).toBe('order_confirmation');
    });
  });

  describe('query by channel', () => {
    it('should return logs for a specific channel', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ channel: 'email' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', channel: 'webhook' }),
        timestamp: new Date(),
      });

      const emailLogs = service.getByChannel('email');
      expect(emailLogs).toHaveLength(1);
      expect(emailLogs[0]!.channel).toBe('email');
    });
  });

  describe('query by date range', () => {
    it('should return logs within a date range', async () => {
      const jan1 = new Date('2026-01-01T00:00:00Z');
      const feb1 = new Date('2026-02-01T00:00:00Z');
      const mar1 = new Date('2026-03-01T00:00:00Z');

      // Manually save logs with specific dates to control createdAt
      repo.save({
        id: 'nlog-0001',
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order 1',
        status: 'sent',
        createdAt: jan1,
      });
      repo.save({
        id: 'nlog-0002',
        notificationId: 'notif-0002',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'sent',
        createdAt: mar1,
      });

      const janLogs = service.getByDateRange(
        new Date('2025-12-31T00:00:00Z'),
        feb1,
      );
      expect(janLogs).toHaveLength(1);
      expect(janLogs[0]!.notificationId).toBe('notif-0001');
    });
  });

  describe('combined query', () => {
    it('should filter by multiple criteria', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({
          recipient: 'alice@example.com',
          type: 'order_confirmation',
          channel: 'email',
        }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:failed',
        notification: makeNotification({
          id: 'notif-0002',
          recipient: 'alice@example.com',
          type: 'welcome',
          channel: 'email',
        }),
        error: 'Failed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({
          id: 'notif-0003',
          recipient: 'bob@example.com',
          type: 'order_confirmation',
          channel: 'webhook',
        }),
        timestamp: new Date(),
      });

      const results = service.query({
        recipient: 'alice@example.com',
        status: 'sent',
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.type).toBe('order_confirmation');
    });

    it('should return all logs when no filters provided', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002' }),
        timestamp: new Date(),
      });

      expect(service.query({})).toHaveLength(2);
    });

    it('should filter by type and channel combined', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ type: 'order_confirmation', channel: 'email' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', type: 'order_confirmation', channel: 'webhook' }),
        timestamp: new Date(),
      });

      const results = service.query({ type: 'order_confirmation', channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]!.channel).toBe('webhook');
    });
  });

  describe('getCount', () => {
    it('should return 0 when no logs exist', () => {
      expect(service.getCount()).toBe(0);
    });

    it('should return correct count after logging', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });

      expect(service.getCount()).toBe(1);
    });
  });
});

